 5→interface ToastContainerProps {
 6→  toasts: ToastData[];
 7→  onDismiss: (id: string) => void;
 8→  portalTarget?: HTMLElement | null;
 9→}
10→
11→export function ToastContainer({
12→  toasts,
13→  onDismiss,
14→  portalTarget,
15→}: ToastContainerProps) {
16→  if (toasts.length === 0) return null;
17→
18→  const content = (
19→    <div className="toast-container">
20→      {toasts.map(toast => (
21→        <Toast
22→          key={toast.id}
23→          style={toast.style}
24→          title={toast.title}
25→          message={toast.message}
26→          onDismiss={() => onDismiss(toast.id)}
27→        />
28→      ))}
29→    </div>
30→  );
31→
32→  if (portalTarget) {
33→    return createPortal(content, portalTarget);
34→  }
35→
36→  return content;
37→}
