 94→export function App() {
 95→  const [query, setQuery] = useState('');
 96→  const [selectedIndex, setSelectedIndex] = useState(0);
 97→  const [actionsOpen, setActionsOpen] = useState(false);
 98→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
 99→  const { toasts, show: showToast, hide: hideToast } = useToast();
100→
101→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
102→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
103→  const selectedItem = drilledItem ?? allItems[selectedIndex];
104→
105→  const handleQueryChange = useCallback((value: string) => {
106→    setQuery(value);
107→    setSelectedIndex(0);
108→    setActionsOpen(false);
109→  }, []);
110→
111→  const handleActiveIndexChange = useCallback((index: number) => {
112→    setSelectedIndex(index);
113→    setActionsOpen(false);
114→  }, []);
115→
116→  const handleDrillIn = useCallback(() => {
117→    const item = allItems[selectedIndex];
118→    if (item) {
119→      setDrilledItem(item);
120→      setQuery('');
121→      setActionsOpen(false);
122→      showToast({
123→        style: 'success',
124→        title: `Opened ${item.title}`,
125→      });
126→    }
127→  }, [
128→    allItems,
129→    selectedIndex,
130→    showToast,
131→  ]);
132→
133→  const handleDrillBack = useCallback(() => {
134→    setDrilledItem(null);
135→    setQuery('');
136→    setSelectedIndex(0);
137→    setActionsOpen(false);
138→  }, []);
139→
140→  const breadcrumbs: BreadcrumbItem[] | undefined = drilledItem
141→    ? [
142→        {
143→          label: 'Raycast',
144→          onBack: handleDrillBack,
145→        },
146→        {
147→          label: drilledItem.title,
148→        },
149→      ]
150→    : undefined;
151→
152→  const toggleActions = useCallback(() => {
153→    setActionsOpen(prev => !prev);
154→  }, []);
155→
156→  const closeActions = useCallback(() => {
157→    setActionsOpen(false);
158→  }, []);
159→
160→  useEffect(() => {
161→    function handleKeyDown(e: KeyboardEvent) {
162→      if (e.key === 'k' && e.metaKey) {
163→        e.preventDefault();
164→        setActionsOpen(prev => !prev);
165→      }
166→    }
167→
168→    window.addEventListener('keydown', handleKeyDown);
169→    return () => window.removeEventListener('keydown', handleKeyDown);
170→  }, []);
171→
172→  const detail = selectedItem?.detail;
173→
174→  const dropdownActions = useMemo(
175→    () => [
176→      {
177→        label: 'Open',
178→        shortcut: <Kbd keys={['↵']} />,
179→        onClick: () => {
180→          if (selectedItem) {
181→            showToast({
182→              style: 'success',
183→              title: `Opened ${selectedItem.title}`,
184→            });
185→          }
186→        },
187→      },
188→      {
189→        label: 'Copy Name',
190→        shortcut: (
191→          <Kbd
192→            keys={[
193→              '⌘',
194→              'C',
195→            ]}
196→          />
197→        ),
198→        onClick: () => {
199→          if (selectedItem) {
200→            showToast({
201→              style: 'info',
202→              title: 'Copied to clipboard',
203→              message: selectedItem.title,
204→            });
205→          }
206→        },
207→      },
208→      {
209→        label: 'Show Detail',
210→        shortcut: (
211→          <Kbd
212→            keys={[
213→              '⌘',
214→              'D',
215→            ]}
216→          />
217→        ),
218→        onClick: () => {
219→          showToast({
220→            style: 'info',
221→            title: 'Detail panel toggled',
222→          });
223→        },
224→      },
225→      {
226→        label: 'Delete',
227→        shortcut: (
228→          <Kbd
229→            keys={[
230→              '⌘',
231→              '⌫',
232→            ]}
233→          />
234→        ),
235→        onClick: () => {
236→          showToast({
237→            style: 'error',
238→            title: 'Cannot delete',
239→            message: 'This item is read-only',
240→          });
241→        },
242→      },
243→    ],
244→    [
245→      selectedItem,
246→      showToast,
247→    ],
248→  );
249→
250→  return (
251→    <CommandPalette isLoading>
252→      <SearchBar
253→        value={query}
254→        onChange={handleQueryChange}
255→        activeDescendantId={
256→          allItems.length > 0 ? `list-item-${selectedIndex}` : undefined
257→        }
258→        breadcrumbs={breadcrumbs}
259→      />
260→      <div
261→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
262→      >
263→        <div className="command-palette__list-container">
264→          {allItems.length === 0 ? (
265→            <EmptyState
266→              icon={<SearchIcon />}
267→              title="No Results"
268→              description="Try a different search term"
269→            />
270→          ) : (
271→            <List
272→              itemCount={allItems.length}
273→              onActiveIndexChange={handleActiveIndexChange}
274→              onAction={handleDrillIn}
275→            >
276→              {(() => {
277→                let globalIndex = 0;
278→                return filtered.map(section => (
279→                  <ListSection key={section.title} title={section.title}>
280→                    {section.items.map(item => {
281→                      const idx = globalIndex++;
282→                      return (
283→                        <ListItem
284→                          key={item.id}
285→                          index={idx}
286→                          title={item.title}
287→                          subtitle={item.subtitle}
288→                          icon={item.icon}
289→                          accessories={item.accessories}
290→                        />
291→                      );
292→                    })}
293→                  </ListSection>
294→                ));
295→              })()}
296→            </List>
297→          )}
298→        </div>
299→        {detail && (
300→          <Detail
301→            markdown={detail.markdown}
302→            metadata={
303→              detail.metadata ? (
304→                <DetailMetadata>
305→                  {detail.metadata.map(renderMetadataEntry)}
306→                </DetailMetadata>
307→              ) : undefined
308→            }
309→          />
310→        )}
311→      </div>
312→      <ActionPanel
313→        actions={[
314→          {
315→            label: 'Open',
316→            shortcut: <Kbd keys={['↵']} />,
317→          },
318→          {
319→            label: 'Actions',
320→            shortcut: (
321→              <Kbd
322→                keys={[
323→                  '⌘',
324→                  'K',
325→                ]}
326→              />
327→            ),
328→            onClick: toggleActions,
329→          },
330→        ]}
331→        dropdownOpen={actionsOpen}
332→        dropdownActions={dropdownActions}
333→        onDropdownClose={closeActions}
334→      />
335→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
336→    </CommandPalette>
337→  );
338→}
